set-variable.value:
@{
                var inputText  = context.Request.Body.As<string>(preserveContent: true);
                var excCats    = context.Variables.GetValueOrDefault<string>("piiExcludedCategories", "[]");
                var language   = context.Variables.GetValueOrDefault<string>("piiDetectionLanguage", "en");
                var failClosed = context.Variables.GetValueOrDefault<string>("piiFailClosed", "false") == "true";
                var scanRoles  = context.Variables.GetValueOrDefault<string>("piiScanRoles", "[\"user\",\"assistant\",\"tool\"]");

                JArray excludedArr;
                try { excludedArr = JArray.Parse(excCats); } catch { excludedArr = new JArray(); }

                JArray scanRolesArr;
                try { scanRolesArr = JArray.Parse(scanRoles); }
                catch { scanRolesArr = new JArray(new[] { "user", "assistant", "tool" }); }

                var configObj = new JObject(
                    new JProperty("fail_closed",         failClosed),
                    new JProperty("excluded_categories", excludedArr),
                    new JProperty("detection_language",  language),
                    new JProperty("scan_roles",          scanRolesArr),
                    new JProperty("correlation_id",      context.RequestId.ToString())
                );

                var bodyJson = string.IsNullOrWhiteSpace(inputText) ? "{}" : inputText;
                return "{\"body\":" + bodyJson + ",\"config\":" + configObj.ToString(Newtonsoft.Json.Formatting.None) + "}";
            }

send-request.set-body:
@{
                    var inputText  = context.Request.Body.As<string>(preserveContent: true);
                    var excCats    = context.Variables.GetValueOrDefault<string>("piiExcludedCategories", "[]");
                    var language   = context.Variables.GetValueOrDefault<string>("piiDetectionLanguage", "en");
                    var failClosed = context.Variables.GetValueOrDefault<string>("piiFailClosed", "false") == "true";
                    var scanRoles  = context.Variables.GetValueOrDefault<string>("piiScanRoles", "[\"user\",\"assistant\",\"tool\"]");

                    JArray excludedArr;
                    try { excludedArr = JArray.Parse(excCats); } catch { excludedArr = new JArray(); }

                    JArray scanRolesArr;
                    try { scanRolesArr = JArray.Parse(scanRoles); }
                    catch { scanRolesArr = new JArray(new[] { "user", "assistant", "tool" }); }

                    var configObj = new JObject(
                        new JProperty("fail_closed",         failClosed),
                        new JProperty("excluded_categories", excludedArr),
                        new JProperty("detection_language",  language),
                        new JProperty("scan_roles",          scanRolesArr),
                        new JProperty("correlation_id",      context.RequestId.ToString())
                    );

                    var bodyJson = string.IsNullOrWhiteSpace(inputText) ? "{}" : inputText;
                    return "{\"body\":" + bodyJson + ",\"config\":" + configObj.ToString(Newtonsoft.Json.Formatting.None) + "}";
                }

set-variable.value:
@{
                try {
                    var r = context.Variables.GetValueOrDefault<IResponse>("piiExternalResponse");
                    return r != null ? ((int)r.StatusCode).ToString() : "0";
                } catch { return "0"; }
            }

@{
                var ticks = context.Variables.GetValueOrDefault<long>("piiStartTimeTicks", DateTime.UtcNow.Ticks);
                return ((DateTime.UtcNow.Ticks - ticks) / TimeSpan.TicksPerMillisecond).ToString();
            }

@{
                var code = context.Variables.GetValueOrDefault<string>("piiDetectionStatusCode", "0");
                if (code != "200") { return "{}"; }
                try {
                    var r = context.Variables.GetValueOrDefault<IResponse>("piiExternalResponse");
                    return r != null ? (r.Body.As<string>(preserveContent: true) ?? "{}") : "{}";
                } catch { return "{}"; }
            }

when.condition:
@{
                    try {
                        var code = context.Variables.GetValueOrDefault<string>("piiDetectionStatusCode", "0");
                        if (code != "200") { return false; }
                        var body = context.Variables.GetValueOrDefault<string>("piiExternalBodyStr", "");
                        if (string.IsNullOrEmpty(body)) { return false; }
                        var obj = JObject.Parse(body);
                        return obj["status"]?.ToString() == "ok"
                            && obj["full_coverage"]?.Value<bool>() == true
                            && obj["redacted_body"] != null;
                    } catch { return false; }
                }

set-variable.value:
@{
                        var body = context.Variables.GetValueOrDefault<string>("piiExternalBodyStr", "");
                        var redacted = JObject.Parse(body)["redacted_body"].ToString(Newtonsoft.Json.Formatting.None);
                        // Guard: if the original body had messages but redacted_body has none,
                        // the request body was lost in transit (APIM body-parse failure → empty JObject).
                        // Fall back to the original request body to avoid sending messages:[] to Azure OAI.
                        try {
                            var orig     = context.Request.Body.As<string>(preserveContent: true);
                            var origMsgs = JObject.Parse(orig)["messages"] as JArray;
                            if (origMsgs != null && origMsgs.Count > 0) {
                                var redactedMsgs = JObject.Parse(redacted)["messages"] as JArray;
                                if (redactedMsgs == null || redactedMsgs.Count == 0) {
                                    return orig;
                                }
                            }
                        } catch { }
                        return redacted;
                    }

@{
                        var orig = context.Request.Body.As<string>(preserveContent: true);
                        var anon = context.Variables.GetValueOrDefault<string>("piiAnonymizedContent", "");
                        return (!string.IsNullOrEmpty(anon) && orig != anon) ? "true" : "false";
                    }

@{
                        try {
                            var body = context.Variables.GetValueOrDefault<string>("piiExternalBodyStr", "");
                            var obj = JObject.Parse(body);
                            return (obj["diagnostics"] ?? new JObject()).ToString(Newtonsoft.Json.Formatting.None);
                        } catch { return "{}"; }
                    }

@{
                        var code = context.Variables.GetValueOrDefault<string>("piiDetectionStatusCode", "0");
                        if (code == "0") { return "no-response"; }
                        if (code == "413") { return "payload-too-large"; }
                        if (code != "200") { return "http-" + code; }
                        try {
                            var body = context.Variables.GetValueOrDefault<string>("piiExternalBodyStr", "");
                            var obj  = JObject.Parse(body);
                            var svcErr = obj["error"]?.ToString() ?? "";
                            return string.IsNullOrEmpty(svcErr) ? "incomplete-coverage" : ("service-error: " + svcErr);
                        } catch { return "incomplete-coverage"; }
                    }

return-response.set-body:
@{
                                    var reason = context.Variables.GetValueOrDefault<string>("piiFailureReason", "unknown");
                                    return new JObject(
                                        new JProperty("error", new JObject(
                                            new JProperty("code",           "PiiRedactionFailed"),
                                            new JProperty("message",        "PII redaction could not be completed and fail-closed policy is in effect."),
                                            new JProperty("request_id",     context.RequestId.ToString()),
                                            new JProperty("failure_reason", reason)
                                        ))
                                    ).ToString(Newtonsoft.Json.Formatting.None);
                                }
